+					tableProps,
+					defaultPartitionName,
+					partition);
+		}
+
+		@Override
+		public TypeSerializer<T> getTypeSerializer() {
+			return typeSerializer;
+		}
+
+		@Override
+		public T getConsumeStartOffset() {
+			return consumeStartOffset;
+		}
